/* =========================================================
   CORES COMPARTILHADAS
   ========================================================= */

.nrdb-ui-group.history-container {
    --history-card-bg: rgba(255, 255, 255, 0.35);
    --history-border: rgba(128, 128, 128, 0.30);
    --history-divider: rgba(128, 128, 128, 0.20);
    --history-hover: rgba(128, 128, 128, 0.08);

    grid-column: 1 / -1 !important;

    width: min(85vw, 1350px) !important;
    max-width: none !important;

    margin: 20px auto !important;
    justify-self: center !important;

    box-sizing: border-box;
}

/* Remove o fundo externo do grupo */
.nrdb-ui-group.history-container > .v-card {
    background: transparent !important;
    border: none !important;
    box-shadow: none !important;
}

/* =========================================================
   CARD BASE: GRÁFICO E TABELA
   ========================================================= */

.history-card,
.history-table-card {
    width: 100% !important;
    margin: 0 0 18px 0 !important;

    background-color: var(--history-card-bg) !important;

    border: 1px solid var(--history-border) !important;
    border-radius: 14px !important;

    box-sizing: border-box !important;
    overflow: hidden !important;

    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.04) !important;

    transition:
        border-color 0.25s ease,
        box-shadow 0.25s ease;
}

/* =========================================================
   GRÁFICO
   ========================================================= */

.history-chart {
    min-height: 330px;
    padding: 14px !important;
}

/* =========================================================
   TABELA: CONTÊINERES INTERNOS
   Todos transparentes para exibir o fundo do card
   ========================================================= */

.history-table-card > .v-card,
.history-table-card .v-card,
.history-table-card .v-data-table,
.history-table-card .v-table,
.history-table-card .v-table__wrapper,
.history-table-card .v-data-table__wrapper {
    width: 100% !important;

    color: rgb(var(--v-theme-on-background)) !important;
    background: transparent !important;

    border: none !important;
    box-shadow: none !important;
}

.history-table-card .v-table__wrapper,
.history-table-card .v-data-table__wrapper {
    overflow-x: auto;
}

/* =========================================================
   PESQUISA
   ========================================================= */

.history-table-card .v-input,
.history-table-card .v-input__control,
.history-table-card .v-field,
.history-table-card .v-field__field,
.history-table-card .v-field__input,
.history-table-card .v-field__outline,
.history-table-card .v-field__loader {
    color: inherit !important;
    background: transparent !important;
}

.history-table-card .v-field__overlay {
    background: transparent !important;
    opacity: 0 !important;
}

.history-table-card .v-field {
    border-bottom: 1px solid var(--history-divider) !important;
    box-shadow: none !important;
}

.history-table-card .v-input:first-child .v-field {
    border-top-left-radius: 14px !important;
    border-top-right-radius: 14px !important;
}

/* =========================================================
   CABEÇALHO
   ========================================================= */

.history-table-card thead,
.history-table-card thead tr,
.history-table-card thead th {
    color: inherit !important;
    background: transparent !important;
}

.history-table-card thead th {
    font-weight: 700 !important;
    border-bottom: 1px solid var(--history-border) !important;
}

/* =========================================================
   CORPO DA TABELA
   ========================================================= */

.history-table-card tbody,
.history-table-card tbody tr,
.history-table-card tbody td {
    color: inherit !important;
    background: transparent !important;
}

.history-table-card tbody td {
    border-bottom: 1px solid var(--history-divider) !important;
    transition: background-color 0.2s ease;
}

/* Hover discreto, sem alterar permanentemente o fundo */
.history-table-card tbody tr:hover,
.history-table-card tbody tr:hover td {
    background-color: var(--history-hover) !important;
}

.history-table-card tbody tr:last-child td {
    border-bottom: none !important;
}

/* =========================================================
   RODAPÉ E PAGINAÇÃO
   ========================================================= */

.history-table-card .v-data-table-footer,
.history-table-card .v-data-table-footer *,
.history-table-card .v-data-table-footer .v-input,
.history-table-card .v-data-table-footer .v-field,
.history-table-card .v-data-table-footer .v-field__field,
.history-table-card .v-data-table-footer .v-field__input {
    color: inherit !important;
    background: transparent !important;
}

.history-table-card .v-data-table-footer {
    border-top: 1px solid var(--history-divider) !important;
}

.history-table-card .v-data-table-footer .v-field__overlay {
    background: transparent !important;
    opacity: 0 !important;
}

.history-table-card button,
.history-table-card .v-btn {
    color: inherit !important;
    background: transparent !important;
}

/* =========================================================
   INTERAÇÃO
   ========================================================= */

.history-card:hover,
.history-table-card:hover {
    border-color: rgba(128, 128, 128, 0.45) !important;
    box-shadow: 0 4px 14px rgba(0, 0, 0, 0.08) !important;
}

/* =========================================================
   RESPONSIVIDADE
   ========================================================= */

@media (max-width: 900px) {
    .nrdb-ui-group.history-container {
        width: calc(100% - 24px) !important;
        margin: 12px auto !important;
    }

    .history-table-card {
        margin-bottom: 12px !important;
        border-radius: 10px !important;
    }

    .history-table-card .v-input:first-child .v-field {
        border-top-left-radius: 10px !important;
        border-top-right-radius: 10px !important;
    }
}
